sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    /**
	GEM/Duypd - 14.05.2026:
	TAM/Sprint 3/Story TAM_43
	When field candidateId changes value, 
	Call script include TAMCandidateInfoAJAX to get candidate info
	Use g_form to set field 
    */

    function onChange(control, oldValue, newValue, isLoading, isTemplate) {
        if (isLoading || newValue === '') {
            return;
        }

        var gaCheckin = new GlideAjax('TAMCandidateInfoAJAX');
        gaCheckin.addParam('sysparm_name', 'getCandidateInfomation');
        gaCheckin.addParam('sysparm_candidate_id', newValue);
        gaCheckin.getXMLAnswer(function(response) {
            var result = JSON.parse(response);
            g_form.setValue('u_bid_candidate_id.u_username', result.candidateUsername);
            g_form.setValue('u_bid_candidate_id.u_email', result.candidatePhonenumber);
        });
    }
}
